"use client";

import React, { useEffect, useState } from 'react';
import { useRouter } from 'next/navigation';
import { FadeIn, SlideUp, StaggerContainer, StaggerItem } from '@/components/animations/MotionUtils';
import { apiClient, ApiError } from '@/lib/apiClient';
import { useAuth } from '@/lib/authContext';

// ── Types ───────────────────────────────────────────────────────────────
interface Course { id: string; title: string; }
interface Enrollment { course: Course; }
interface StudentProfile { enrollments: Enrollment[]; }
interface UserProfile {
  id: string;
  name: string;
  email: string;
  studentProfile: StudentProfile | null;
}
interface TestResult {
  id: string;
  testName: string;
  marksObtained: number;
  totalMarks: number;
  testDate: string;
}
interface Announcement { label: string; text: string; priority: 'important' | 'notice'; }

// ── Skeleton (Institutional Style) ─────────────────────────────────────────
const Skeleton = ({ className = '' }: { className?: string }) => (
  <div className={`animate-pulse bg-white/5 border border-white/5 ${className}`} />
);

export default function DashboardPage() {
  const router = useRouter();
  const { user: authUser, isLoading: authLoading } = useAuth();

  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [testResults, setTestResults] = useState<TestResult[]>([]);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!authLoading && !authUser) {
      router.push('/login');
    }
  }, [authUser, authLoading, router]);

  useEffect(() => {
    if (!authUser) return;
    const fetchData = async () => {
      setLoading(true);
      try {
        const [profileData, testsData] = await Promise.all([
          apiClient.get<UserProfile>('/portal/me'),
          apiClient.get<TestResult[]>('/portal/tests'),
        ]);
        setProfile(profileData);
        setTestResults(testsData);
      } catch (err) {
        if (err instanceof ApiError && err.status === 401) {
          router.push('/login');
        } else {
          setError('INSTITUTIONAL_ERROR: DATA_COMM_FAILURE');
        }
      } finally {
        setLoading(false);
      }
    };
    fetchData();
  }, [authUser, router]);

  const firstName = profile?.name?.split(' ')[0] ?? authUser?.name?.split(' ')[0] ?? 'STUDENT';
  const enrolledCourse = profile?.studentProfile?.enrollments?.[0]?.course?.title ?? 'ACTIVE_NODE_NULL';
  const recentTests = testResults.slice(0, 3);

  const announcements: Announcement[] = [
    { priority: 'important', label: 'URGENT', text: 'PRACTICE_SHEETS_UPLOADED_TO_MATERIALS_REPOSITORY.' },
    { priority: 'notice', label: 'NOTICE', text: 'DOUBT_CLEARING_SESSION_SCHEDULE_PRACTICE_V1.' },
  ];

  if (authLoading || (!profile && loading)) {
    return (
      <div className="space-y-12">
        <div className="flex flex-col">
           <Skeleton className="h-4 w-32 mb-4" />
           <Skeleton className="h-32 w-full mb-8" />
        </div>
        <div className="grid grid-cols-1 md:grid-cols-3 gap-8">
           <Skeleton className="h-48" />
           <Skeleton className="h-48" />
           <Skeleton className="h-48" />
        </div>
        <div className="grid lg:grid-cols-12 gap-12 pt-12">
           <Skeleton className="lg:col-span-8 h-[600px]" />
           <Skeleton className="lg:col-span-4 h-[600px]" />
        </div>
      </div>
    );
  }

  if (error) {
    return (
      <div className="max-w-2xl mx-auto py-48 text-center bg-white/[0.02] border border-white/5 p-12">
        <span className="text-2xl font-black text-red-500 uppercase tracking-tighter mb-4 block">TERMINAL_CRASH</span>
        <p className="text-xs font-bold text-[#888888] uppercase tracking-[0.5em]">{error}</p>
        <button onClick={() => window.location.reload()} className="mt-12 text-[10px] font-bold uppercase tracking-[0.3em] text-white hover:underline underline-offset-8">
           [ INITIALIZE_REBOOT ]
        </button>
      </div>
    );
  }

  return (
    <div className="space-y-24 pb-32">

      {/* Performance Matrix Header */}
      <FadeIn>
        <div className="flex flex-col items-start leading-[0.85]">
          <span className="font-script text-4xl text-[#888888] lowercase mb-8 block">welcome back,</span>
          <h1 className="text-7xl md:text-9xl font-black uppercase tracking-tighter-editorial text-white">
            Archivist <br /> <span className="text-white/20">{firstName}</span>
          </h1>
          <div className="flex items-center gap-12 mt-12">
             <div className="flex flex-col">
               <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-1">PROGRAM_NODE</span>
               <span className="text-sm font-black text-white uppercase tracking-widest">{enrolledCourse}</span>
             </div>
             <div className="w-12 h-px bg-white/20" />
             <div className="flex items-center gap-4">
               <div className="w-2 h-2 bg-green-500 rounded-full animate-pulse" />
               <span className="text-[9px] font-bold text-white/40 uppercase tracking-[0.4em]">SESSION_ACTIVE</span>
             </div>
          </div>
        </div>
      </FadeIn>

      {/* Metric Bento Tiles */}
      <StaggerContainer className="grid grid-cols-1 md:grid-cols-3 gap-0">
        <StaggerItem>
          <div className="border border-white/5 p-12 group hover:bg-white/[0.02] transition-all duration-700 h-full relative overflow-hidden">
            <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-8 block italic">KPI_01: ENROLLMENT_STATE</span>
            <div className="flex items-baseline gap-4 mt-8">
               <h3 className="text-5xl font-black text-white uppercase tracking-tighter line-clamp-1">{enrolledCourse}</h3>
            </div>
            <div className="absolute -bottom-px left-0 w-0 h-px bg-white group-hover:w-full transition-all duration-700" />
          </div>
        </StaggerItem>
        <StaggerItem>
          <div className="border-y border-r md:border-y md:border-r border-white/5 p-12 group hover:bg-white/[0.02] transition-all duration-700 h-full relative overflow-hidden">
            <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-8 block italic">KPI_02: CUMULATIVE_TESTS</span>
            <div className="flex items-baseline gap-4 mt-8">
               <h3 className="text-7xl font-black text-white uppercase tracking-tighter">{testResults.length}</h3>
               <span className="text-xs font-black text-white/20 uppercase tracking-widest">LOGS_RECORDED</span>
            </div>
            <div className="absolute -bottom-px left-0 w-0 h-px bg-white group-hover:w-full transition-all duration-700" />
          </div>
        </StaggerItem>
        <StaggerItem>
          <div className="border-y border-r border-white/5 p-12 group hover:bg-white/[0.02] transition-all duration-700 h-full relative overflow-hidden">
            <span className="text-[9px] font-bold text-white/20 uppercase tracking-[0.4em] mb-8 block italic">KPI_03: PERFORMANCE_ID</span>
            <div className="flex items-baseline gap-4 mt-8">
               <h3 className="text-7xl font-black text-white uppercase tracking-tighter">
                {testResults.length > 0
                  ? `${Math.round(testResults.reduce((sum, t) => sum + (t.marksObtained / t.totalMarks) * 100, 0) / testResults.length)}%`
                  : 'N/A'}
               </h3>
               <span className="text-xs font-black text-white/20 uppercase tracking-widest">AVG_PRECISION</span>
            </div>
            <div className="absolute -bottom-px left-0 w-0 h-px bg-white group-hover:w-full transition-all duration-700" />
          </div>
        </StaggerItem>
      </StaggerContainer>

      <div className="grid lg:grid-cols-12 gap-16">

        {/* Test Matrix Archive */}
        <div className="lg:col-span-8">
          <SlideUp>
            <div className="flex items-center justify-between mb-16 px-4">
              <span className="text-[10px] font-black uppercase tracking-[0.5em] text-white/20 italic">02. PERFORMANCE_ARCHIVE</span>
              <a href="/portal/test-results" className="text-[8px] font-bold uppercase tracking-[0.3em] text-[#888888] hover:text-white transition-colors">
                [ ACCESS_FULL_ANALYTICS ]
              </a>
            </div>
            
            {recentTests.length === 0 ? (
              <div className="p-16 border border-white/5 bg-white/[0.01] text-center">
                <p className="text-[10px] font-bold uppercase tracking-[0.3em] text-[#555555]">ARCHIVE_EMPTY: NO_LOGS_DETECTED</p>
              </div>
            ) : (
              <div className="flex flex-col divide-y divide-white/5 border-y border-white/5">
                {recentTests.map((test) => (
                  <div key={test.id} className="group flex flex-col md:flex-row justify-between items-start md:items-center py-12 px-4 hover:bg-white/[0.01] transition-all duration-500">
                    <div className="flex flex-col mb-4 md:mb-0">
                       <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.2em] mb-1">ID: {test.id.slice(0,8)}</span>
                       <h3 className="text-3xl font-black text-white uppercase tracking-tighter group-hover:pl-4 transition-all duration-500">{test.testName}</h3>
                    </div>
                    
                    <div className="flex items-center gap-12 w-full md:w-auto">
                      <div className="flex flex-col items-end hidden md:flex">
                        <span className="text-[8px] font-black text-white/10 uppercase tracking-[0.2em] mb-1">MARK_ID</span>
                        <span className="text-2xl font-black text-white tracking-tighter italic">{test.marksObtained}/{test.totalMarks}</span>
                      </div>
                      <div className="w-48 h-1 bg-white/[0.05] relative overflow-hidden flex-1 md:flex-none">
                         <div 
                           className="absolute left-0 top-0 h-full bg-white transition-all duration-[1500ms] ease-expo group-hover:opacity-60" 
                           style={{ width: `${(test.marksObtained / test.totalMarks) * 100}%` }}
                         />
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            )}
          </SlideUp>
        </div>

        {/* Global Notices Terminal */}
        <div className="lg:col-span-4">
          <SlideUp delay={0.2}>
            <div className="mb-16 px-4">
              <span className="text-[10px] font-black uppercase tracking-[0.5em] text-white/20 italic">03. SYSTEM_NOTICES</span>
            </div>
            <div className="space-y-4">
              {announcements.map((a, i) => (
                <div key={i} className="p-12 border border-white/5 bg-white/[0.02] group hover:bg-white/[0.04] transition-all duration-500">
                   <div className="flex justify-between items-center mb-6">
                      <span className={`text-[8px] font-black uppercase tracking-[0.3em] ${a.priority === 'important' ? 'text-white underline underline-offset-4 decoration-white/30' : 'text-white/20'}`}>
                        {a.label}
                      </span>
                      <div className="w-12 h-px bg-white/5 group-hover:w-full transition-all duration-1000 origin-right" />
                   </div>
                   <p className="text-sm font-black text-[#888888] uppercase tracking-tighter leading-tight group-hover:text-white transition-colors">
                     {a.text}
                   </p>
                </div>
              ))}
              
              <div className="pt-8 text-center">
                 <a href="/portal/materials" className="text-[8px] font-bold uppercase tracking-[0.4em] text-white/10 hover:text-white transition-colors">
                   [ ACCESS_MATERIALS_ARCHIVE ]
                 </a>
              </div>
            </div>
          </SlideUp>
        </div>

      </div>

    </div>
  );
}
